 1	import * as React from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { StatusPopupItem, StatusPopupSection } from '@openshift-console/dynamic-plugin-sdk';
 5	import { Stack, StackItem } from '@patternfly/react-core';
 6	
 7	import { healthStateMapping } from '../utils';
 8	
 9	type StatusCardStoragePopoverProps = {
10	  lsoState: any;
11	  odfState: any;
12	};
13	
14	const StatusCardStoragePopover: React.FC<StatusCardStoragePopoverProps> = ({
15	  lsoState,
16	  odfState,
17	}) => {
18	  const { t } = useKubevirtTranslation();
19	
20	  return (
21	    <Stack hasGutter>
22	      <StackItem>
23	        {t(
24	          'OpenShift Data Foundation (recommended for full functionality) or another persistent storage service is required for OpenShift Virtualization',
25	        )}
26	      </StackItem>
27	      <StackItem>
28	        <StatusPopupSection firstColumn={t('Storage operator')} secondColumn={t('Status')}>
29	          <StatusPopupItem
30	            icon={healthStateMapping[lsoState.state].icon}
31	            key="lso"
32	            value={lsoState.message}
33	          >
34	            {t('Local storage (LSO)')}
35	          </StatusPopupItem>
36	          <StatusPopupItem
37	            icon={healthStateMapping[odfState.state].icon}
38	            key="odf"
39	            value={odfState.message}
40	          >
41	            {t('OpenShift Data Foundation (ODF)')}
42	          </StatusPopupItem>
43	        </StatusPopupSection>
44	      </StackItem>
45	    </Stack>
46	  );
47	};
48	
49	export default StatusCardStoragePopover;

